custom_css:
.minha-logo, .minha-logo span { 
    font-size: 30px; 
    font-weight: 900; 
    font-style: italic;
    color: #ff5e8e;
    text-shadow: 2px 2px 0px #ffffff;
    letter-spacing: -1px;
    display: inline-block;
    animation: bunny-hop 1.2s infinite ease-in-out;
}

@keyframes bunny-hop {
    0%, 100% { 
        transform: translateY(0) scale(1, 1); 
    }
    30% { 
        transform: translateY(-12px) scale(0.9, 1.1);
    }
    50% { 
        transform: translateY(0) scale(1.05, 0.95);
    }
}
